mapper.select:
SELECT a.id, a.author_id, a.title, a.content_text, a.content_storage_type, a.content_object_key, a.content_url, a.content_format, a.content_preview, a.cover_url, a.like_count, a.favorite_count, a.summary_status, a.summary_text, a.created_at, a.updated_at, up.nickname AS author_nickname, up.avatar_url AS author_avatar_url FROM article a LEFT JOIN user_profile up ON up.id = a.author_id WHERE a.status = 1
AND a.author_id = #{authorId}
ORDER BY a.published_at DESC, a.id DESC LIMIT #{limit} OFFSET #{offset}
